// TestNovelForecastHelpWires smoke-tests that the forecast command
// resolves at runtime and renders --help without error.
func TestNovelForecastHelpWires(t *testing.T) {
	cmd := RootCmd()
	cmd.SetArgs([]string{"forecast", "--help"})
	cmd.SetOut(io.Discard)
	cmd.SetErr(io.Discard)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("forecast --help error = %v (novel command not wired correctly?)", err)
	}
}

// seedOpp inserts one opportunity record (typed columns + JSON data) into a
// fresh store. extra fields are merged into the JSON body so json_extract
// reads (assignee_id etc.) resolve in tests.
func seedOpp(t *testing.T, s *store.Store, id string, fields map[string]any) {
	t.Helper()
	if fields == nil {
		fields = map[string]any{}
	}
	fields["id"] = id
	data, err := json.Marshal(fields)
	if err != nil {
		t.Fatalf("marshal opp %s: %v", id, err)
	}
	if err := s.UpsertOpportunities(data); err != nil {
		t.Fatalf("upsert opp %s: %v", id, err)
	}
}

func newTestStore(t *testing.T) *store.Store {
	t.Helper()
	dbPath := filepath.Join(t.TempDir(), "data.db")
	s, err := store.Open(dbPath)
	if err != nil {
		t.Fatalf("store.Open: %v", err)
	}
	t.Cleanup(func() { _ = s.Close() })
	return s
}

func TestNovelForecastBehavior(t *testing.T) {
	s := newTestStore(t)
	// Two open opps in stage 9: 1000 @ 50% and 2000 @ 25%.
	seedOpp(t, s, "1", map[string]any{
		"pipeline_id": 12, "pipeline_stage_id": 9,
		"monetary_value": 1000.0, "win_probability": 50, "status": "Open",
		"assignee_id": 700, "close_date": "2026-07-15",
	})
	seedOpp(t, s, "2", map[string]any{
		"pipeline_id": 12, "pipeline_stage_id": 9,
		"monetary_value": 2000.0, "win_probability": 25, "status": "Open",
		"assignee_id": 701, "close_date": "2026-08-15",
	})
	// One won opp that must be excluded by the status filter.
	seedOpp(t, s, "3", map[string]any{
		"pipeline_id": 12, "pipeline_stage_id": 9,
		"monetary_value": 9999.0, "win_probability": 100, "status": "Won",
	})

	rows, err := runForecast(context.Background(), s.DB(), forecastOpts{By: "stage", Status: "Open"})
	if err != nil {
		t.Fatalf("runForecast: %v", err)
	}
	if len(rows) != 1 {
		t.Fatalf("want 1 group, got %d: %+v", len(rows), rows)
	}
	r := rows[0]
	if r.Group != "9" {
		t.Errorf("group = %q, want \"9\"", r.Group)
	}
	// weighted = 1000*0.5 + 2000*0.25 = 500 + 500 = 1000
	if r.WeightedValue != 1000 {
		t.Errorf("weighted_value = %v, want 1000", r.WeightedValue)
	}
	if r.OpenValue != 3000 {
		t.Errorf("open_value = %v, want 3000", r.OpenValue)
	}
	if r.Count != 2 {
		t.Errorf("count = %d, want 2", r.Count)
	}

	// Group by assignee → two buckets, each one opp.
	byAssignee, err := runForecast(context.Background(), s.DB(), forecastOpts{By: "assignee", Status: "Open"})
	if err != nil {
		t.Fatalf("runForecast assignee: %v", err)
	}
	if len(byAssignee) != 2 {
		t.Fatalf("assignee groups = %d, want 2: %+v", len(byAssignee), byAssignee)
	}

	// Pipeline filter that matches nothing → empty.
	none, err := runForecast(context.Background(), s.DB(), forecastOpts{By: "stage", Status: "Open", Pipeline: "999"})
	if err != nil {
		t.Fatalf("runForecast pipeline filter: %v", err)
	}
	if len(none) != 0 {
		t.Errorf("pipeline 999 groups = %d, want 0", len(none))
	}
}

// TestNovelForecastCloseMonthBuckets verifies close_date in MM/DD/YYYY form is
// bucketed into a correct YYYY-MM group (regression for substr(1,7) mis-bucketing).
func TestNovelForecastCloseMonthBuckets(t *testing.T) {
	s := newTestStore(t)
	seedOpp(t, s, "1", map[string]any{"status": "Open", "monetary_value": 100, "win_probability": 50, "close_date": "12/20/2025"})
	seedOpp(t, s, "2", map[string]any{"status": "Open", "monetary_value": 200, "win_probability": 50, "close_date": "12/26/2025"})
	seedOpp(t, s, "3", map[string]any{"status": "Open", "monetary_value": 50, "win_probability": 50, "close_date": "01/05/2026"})

	rows, err := runForecast(context.Background(), s.DB(), forecastOpts{By: "close-month", Status: "Open"})
	if err != nil {
		t.Fatalf("runForecast close-month: %v", err)
	}
	got := map[string]int{}
	for _, r := range rows {
		got[r.Group] = r.Count
	}
	if got["2025-12"] != 2 {
		t.Errorf("2025-12 count = %d, want 2 (rows: %+v)", got["2025-12"], rows)
	}
	if got["2026-01"] != 1 {
		t.Errorf("2026-01 count = %d, want 1 (rows: %+v)", got["2026-01"], rows)
	}
}
